import{_ as d,o,c as t,a3 as c}from"./chunks/framework.BveOjhN0.js";const g=JSON.parse('{"title":"AI 能力","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/basic-app/ai.md","filePath":"cosmos/basic-app/ai.md","lastUpdated":1783300196000}'),a={name:"cosmos/basic-app/ai.md"};function s(i,e,r,n,l,p){return o(),t("div",null,[...e[0]||(e[0]=[c(`<h1 id="ai-能力" tabindex="-1">AI 能力 <a class="header-anchor" href="#ai-能力" aria-label="Permalink to &quot;AI 能力&quot;">​</a></h1><p>BasicApp 的 AI 能力落在独立模块 <code>XiHan.BasicApp.AI</code> 里，与代码生成模块同构（独立工程、独立种子段、独立权限资源）。它坐落在框架薄层 <a href="./../framework/packages/ai">XiHan.Framework.AI</a> 之上：<strong>框架</strong>提供 provider 解析、会话/嵌入门面、RAG 切片检索、Agent 与 MCP 桥接的抽象与默认实现；<strong>BasicApp</strong> 在其上做两件业务落地——把 AI Provider 配置<strong>库化管理</strong>（存库 + 加密 + 前端可维护 + 热切换），以及把 RAG 知识库**接上真实向量库（Qdrant）**并暴露为文档管理 / 检索问答 / MCP 工具。</p><p>模块只依赖 <code>XiHanBasicAppSaasModule</code>（复用 RBAC 表、<code>SaasRepository</code>、DataProtection 密文前缀），框架 AI 经 Saas → Core 传递进来。</p><h2 id="两大能力" tabindex="-1">两大能力 <a class="header-anchor" href="#两大能力" aria-label="Permalink to &quot;两大能力&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>做什么</th><th>关键实体 / 服务</th><th>权限资源</th></tr></thead><tbody><tr><td><strong>Provider 库化管理</strong></td><td>AI 服务商配置存库、加密密钥、CRUD、设默认、测连接、改配置即时热切换</td><td><code>SysAiProvider</code>、<code>AiProviderAppService</code>、<code>SaasAiProviderConfigStore</code></td><td><code>ai</code></td></tr><tr><td><strong>RAG 知识库</strong></td><td>文档摄取（切片 → 嵌入 → 写 Qdrant）、重建索引、语义检索、注入 prompt 生成带引用答案</td><td><code>SysKnowledgeDocument</code>、<code>KnowledgeDocumentAppService</code>、<code>KnowledgeQueryAppService</code></td><td><code>knowledge_base</code></td></tr></tbody></table><p>此外还有一条<strong>Agent / MCP</strong> 支线：知识检索被封装为技能（<code>KnowledgeRetrieveSkill</code>），框架技能注册表自动收纳，进而投影为对话工具与 MCP tools，供外部 AI 客户端（Claude Code / Cursor 等）调用。</p><p>模块前端页面挂在「开发工具（develop）」目录下：<strong>AI 提供商</strong>（<code>/develop/aiProvider</code>）与<strong>知识库</strong>（<code>/develop/knowledge</code>），二者均仅对持有 <code>ai:read</code> / <code>knowledge_base:read</code> 者（默认=超管通配 <code>*</code>）可见。</p><hr><h2 id="provider-库化管理" tabindex="-1">Provider 库化管理 <a class="header-anchor" href="#provider-库化管理" aria-label="Permalink to &quot;Provider 库化管理&quot;">​</a></h2><h3 id="为什么存库而不写-appsettings" tabindex="-1">为什么存库而不写 appsettings <a class="header-anchor" href="#为什么存库而不写-appsettings" aria-label="Permalink to &quot;为什么存库而不写 appsettings&quot;">​</a></h3><p>框架默认的 provider 配置源 <code>OptionsAiProviderConfigStore</code> 读 <code>XiHan:AI</code> 配置节兜底。BasicApp 把它<strong>替换</strong>为数据库实现 <code>SaasAiProviderConfigStore</code>，好处是：配置可在前端维护、天然按租户隔离、密钥加密落库、且改完能不重启热切换。</p><p><code>SysAiProvider</code>（表 <code>Sys_Ai_Provider</code>）关键字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>列</th><th>说明</th></tr></thead><tbody><tr><td><code>ConfigCode</code></td><td><code>Config_Code</code></td><td>配置编码，<strong>租户内唯一</strong>（<code>UX_TeId_CoCd</code>，含 <code>IsDeleted</code> 末列，软删后可复用），上层解析器/配置源以它为 provider 键；<strong>创建后不可变</strong></td></tr><tr><td><code>ConfigName</code></td><td><code>Config_Name</code></td><td>配置名称（展示）</td></tr><tr><td><code>Provider</code></td><td><code>Provider</code></td><td>提供商/协议标识，<strong>自由字符串</strong>（<code>OpenAI</code>/<code>DeepSeek</code>/<code>Azure</code>/<code>vLLM</code>/<code>Custom</code> 等），仅作分组与展示，<strong>不是枚举</strong></td></tr><tr><td><code>Model</code></td><td><code>Model</code></td><td>会话模型名</td></tr><tr><td><code>EmbeddingModel</code></td><td><code>Embedding_Model</code></td><td>嵌入模型名（RAG 用；与会话同端点同密钥、仅模型 id 不同，如 <code>text-embedding-3-small</code>；空则该 provider 不支持嵌入）</td></tr><tr><td><code>BaseUrl</code></td><td><code>Base_Url</code></td><td>端点地址（空则用提供商默认端点，如 OpenAI 官方）</td></tr><tr><td><code>ApiKey</code></td><td><code>Api_Key</code></td><td>API 密钥，<strong>可逆加密落库</strong>，双 <code>[JsonIgnore]</code> 防外泄</td></tr><tr><td><code>MaxOutputTokens</code> / <code>Temperature</code> / <code>TimeoutSeconds</code> / <code>ExtraJson</code></td><td>同名列</td><td>采样与扩展参数，<code>ExtraJson</code> 免改表结构扩展</td></tr><tr><td><code>IsDefault</code></td><td><code>Is_Default</code></td><td>是否默认 provider（<strong>租户内单默认</strong>，软约束）</td></tr><tr><td><code>IsEnabled</code> / <code>Status</code></td><td><code>Is_Enabled</code> / <code>Status</code></td><td>运行开关与状态；禁用或非 <code>Enabled</code> 均不参与配置源解析</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">一个适配器打天下</p><p>OpenAI / DeepSeek / Azure / vLLM / Ollama / 自训模型多数走 OpenAI 兼容协议——<code>BaseUrl</code> 指向对应端点、填 <code>Model</code> 与 <code>ApiKey</code> 即可，无须每家写一个适配器。<code>Provider</code> 字段只是分组标签，真正决定行为的是 <code>BaseUrl</code> + <code>Model</code>。</p></div><h3 id="密钥加密" tabindex="-1">密钥加密 <a class="header-anchor" href="#密钥加密" aria-label="Permalink to &quot;密钥加密&quot;">​</a></h3><p><code>ApiKey</code> 经 <code>DataProtectionAiProviderSecretProtector</code> 用 ASP.NET Core Data Protection 加密，密文带统一前缀，使用<strong>独立 Purpose</strong>（与存储密钥/短信密钥/邮件密码/租户连接串互不影响）。要点：</p><ul><li><strong>写入</strong>：创建时明文提交、服务端加密；更新时 <code>ApiKey</code> <strong>留空表示保留原密钥</strong>，非空才替换重加密。</li><li><strong>读出</strong>：列表/详情 DTO <strong>永不回读密钥</strong>——只暴露布尔标志 <code>HasApiKey</code>；<code>[JsonIgnore]</code> 双注解在实体层再兜一道底。</li><li><strong>解密</strong>：只解本保护器写入的密文，去前缀直接解密，<strong>失败即抛</strong>（fail-closed，不做旧明文兼容）。</li><li><strong>多实例部署</strong>须共享 Data Protection 密钥环（持久化到共享存储），否则其它实例无法解密。</li></ul><h3 id="配置源解析" tabindex="-1">配置源解析 <a class="header-anchor" href="#配置源解析" aria-label="Permalink to &quot;配置源解析&quot;">​</a></h3><p><code>SaasAiProviderConfigStore</code>（Singleton，经 <code>IServiceScopeFactory</code> 开作用域取 Scoped 仓储）实现框架的 <code>IAiProviderConfigStore</code>：</p><ul><li><code>GetAsync(null)</code>：取<strong>默认且启用</strong>行（<code>IsDefault &amp;&amp; IsEnabled &amp;&amp; Status==Enabled</code>，按 <code>Sort</code> 取首条）。</li><li><code>GetAsync(configCode)</code>：按 <code>ConfigCode</code> 取启用行；无匹配返回 <code>null</code>（框架按「未配置」处理）。</li><li><code>GetAllAsync</code>：枚举全部启用行；单行解密失败<strong>跳过并告警</strong>，不阻断全表、不回退明文（fail-closed）。</li><li>映射为框架 <code>AiProviderOptions</code> 时，<strong><code>Provider</code> 键即 <code>ConfigCode</code></strong>，供解析器按此缓存。配置源本身<strong>不做进程内缓存</strong>——缓存在解析器那层。</li></ul><h3 id="热切换-改配置即时生效" tabindex="-1">热切换（改配置即时生效） <a class="header-anchor" href="#热切换-改配置即时生效" aria-label="Permalink to &quot;热切换（改配置即时生效）&quot;">​</a></h3><p>框架解析器（<code>IAiChatClientResolver</code> / <code>IAiEmbeddingGeneratorResolver</code>）按 provider 名缓存构建好的 <code>IChatClient</code> / 嵌入生成器，<strong>不会自动感知 DB 变更</strong>。所以 <code>AiProviderAppService</code> 在<strong>每个写操作后</strong>都调 <code>InvalidateResolvers()</code>：</p><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">private</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> InvalidateResolvers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    _chatClientResolver.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Invalidate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 清空会话客户端缓存</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    _embeddingResolver.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Invalidate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 清空嵌入生成器缓存</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>Create</code> / <code>Update</code> / <code>UpdateStatus</code> / <code>SetDefault</code> / <code>Delete</code> 全部在返回前 <code>Invalidate</code>——下次解析按最新 DB 配置重建，运维改完 key/baseUrl/model <strong>无须重启</strong>即生效。这是「库化管理 + 配置热切换」的闭环关键。</p><h3 id="应用服务动作" tabindex="-1">应用服务动作 <a class="header-anchor" href="#应用服务动作" aria-label="Permalink to &quot;应用服务动作&quot;">​</a></h3><p><code>AiProviderAppService</code>（<code>[DynamicApi]</code>，无 Controller）暴露的动作：</p><table tabindex="0"><thead><tr><th>动作</th><th>权限码</th><th>事务</th><th>说明</th></tr></thead><tbody><tr><td><code>CreateAsync</code></td><td><code>ai:create</code></td><td><code>[UnitOfWork]</code></td><td>新增配置；<code>ConfigCode</code> 不能含空白、租户内不重复</td></tr><tr><td><code>UpdateAsync</code></td><td><code>ai:update</code></td><td><code>[UnitOfWork]</code></td><td>更新；<code>ConfigCode</code> 不可变，<code>ApiKey</code> 留空保留原值</td></tr><tr><td><code>UpdateStatusAsync</code></td><td><code>ai:update</code></td><td><code>[UnitOfWork]</code></td><td>启停状态</td></tr><tr><td><code>SetDefaultAsync</code></td><td><code>ai:update</code></td><td><code>[UnitOfWork]</code></td><td>设为默认（已禁用者不可设默认）；领域服务清除其它行 <code>IsDefault</code>（单默认互斥）</td></tr><tr><td><code>DeleteAsync</code></td><td><code>ai:delete</code></td><td><code>[UnitOfWork]</code></td><td>软删</td></tr><tr><td><code>TestConnectionAsync</code></td><td><code>ai:execute</code></td><td>无</td><td><code>[HttpPost]</code>；用<strong>一次性客户端</strong>（不入解析器缓存）向 provider 发一句 <code>ping</code>，返回成功/耗时/finishReason——<strong>可测尚未启用的配置</strong></td></tr></tbody></table><p>查询侧 <code>AiProviderQueryService</code>：<code>GetPageAsync</code>（<code>[HttpPost]</code>，<code>ai:read</code>，FLS 门控排序/过滤 + 默认兜底排序）与 <code>GetDetailAsync</code>。列表/详情均走 <code>HasApiKey</code> 布尔而非明文。</p><p>采样温度限定 <code>0~2</code>，越界抛异常。</p><hr><h2 id="rag-知识库" tabindex="-1">RAG 知识库 <a class="header-anchor" href="#rag-知识库" aria-label="Permalink to &quot;RAG 知识库&quot;">​</a></h2><p>一条最小可用的 RAG：<strong>摄取</strong>（文档切片 → 嵌入 → 写向量库）与<strong>检索问答</strong>（query 嵌入 → 向量检索 → 注入 prompt → 会话生成带引用答案）。切片与向量落在 <strong>Qdrant</strong>，本模块的 <code>SysKnowledgeDocument</code>（表 <code>Sys_Knowledge_Document</code>）只存文档元信息与<strong>原文</strong>（<code>RawContent</code>，用于免重传重建索引）。</p><h3 id="向量库与嵌入约定-以框架为准" tabindex="-1">向量库与嵌入约定（以框架为准） <a class="header-anchor" href="#向量库与嵌入约定-以框架为准" aria-label="Permalink to &quot;向量库与嵌入约定（以框架为准）&quot;">​</a></h3><p>RAG 的底层实现由框架 <code>AddXiHanRAG()</code> 提供（切片/摄取/检索/增强），BasicApp 负责登记具体向量连接器与嵌入模型选择。以下约定源自框架 <code>VectorStoreKnowledgeRecord</code>，是<strong>部署前必须对齐</strong>的硬约束：</p><table tabindex="0"><thead><tr><th>约定</th><th>值</th><th>说明</th></tr></thead><tbody><tr><td>向量库</td><td><strong>Qdrant</strong>（当前 preview）</td><td>BasicApp 经 <code>AddQdrantVectorStore(...)</code> 登记（gRPC），框架本身不引用 Qdrant</td></tr><tr><td>集合名</td><td><code>xihan_knowledge</code></td><td>固定常量</td></tr><tr><td>主键</td><td><code>Guid</code>（Qdrant 只支持 <code>Guid</code>/<code>ulong</code> 键）</td><td>由 <code>MD5(documentId:index)</code> <strong>确定性派生</strong>——同文档同序号恒等，重复摄取即覆盖（幂等）</td></tr><tr><td>嵌入模型</td><td>取自 <code>SysAiProvider.EmbeddingModel</code></td><td>与会话同端点同密钥、仅模型 id 不同；空则该 provider 不支持嵌入</td></tr><tr><td>向量维度</td><td><strong><code>1536</code>（编译期常量，硬编码）</strong></td><td>对齐 <code>text-embedding-3-small</code>。换用不同维度的嵌入模型<strong>必须改框架常量并重建集合</strong>，否则维度不匹配</td></tr><tr><td>距离 / 索引</td><td><code>CosineSimilarity</code> / <code>Hnsw</code></td><td>—</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">换嵌入模型 = 改常量 + 重建集合</p><p>维度 <code>1536</code> 是框架编译期常量。若换到维度不同的嵌入模型（如某些 1024/3072 维模型），仅在前端改 <code>EmbeddingModel</code> 会导致 upsert/检索维度不匹配。这属于需改框架源码并重建 Qdrant 集合的动作，不是运行期配置项。拿不准的维度<strong>以仓库为准</strong>。</p></div><h3 id="文档摄取与索引" tabindex="-1">文档摄取与索引 <a class="header-anchor" href="#文档摄取与索引" aria-label="Permalink to &quot;文档摄取与索引&quot;">​</a></h3><p><code>SysKnowledgeDocument</code> 关键字段：<code>Title</code>、<code>SourceType</code>（<code>PasteText</code> / <code>UploadFile</code>，上传文件由前端读为文本后提交）、<code>Source</code>（文件名/标签，引用溯源用）、<code>RawContent</code>（原文）、<code>ChunkCount</code>（已入库切片数）、<code>EmbeddingProviderCode</code>（嵌入 provider 编码，空=默认 provider）、<code>Status</code>（<code>Pending</code> / <code>Indexed</code> / <code>Failed</code>）、<code>ErrorMessage</code>。</p><p><code>KnowledgeDocumentAppService</code> 动作（均 <code>[HttpPost]</code> 除删除）：</p><table tabindex="0"><thead><tr><th>动作</th><th>权限码</th><th>说明</th></tr></thead><tbody><tr><td><code>IngestAsync</code></td><td><code>knowledge_base:create</code></td><td>摄取：落库 <code>Pending</code> → 切片嵌入写 Qdrant → 回写 <code>Indexed</code>/<code>Failed</code></td></tr><tr><td><code>ReindexAsync</code></td><td><code>knowledge_base:update</code></td><td>重建：先按当前 <code>ChunkCount</code> 清旧向量，再用 <code>RawContent</code> 重新索引</td></tr><tr><td><code>DeleteAsync</code></td><td><code>knowledge_base:delete</code></td><td>先删向量再删文档</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">摄取不套 UnitOfWork</p><p>摄取/重建含外部 I/O（嵌入 API + 向量库网络调用），领域服务<strong>刻意不套 <code>[UnitOfWork]</code></strong>：先落库 <code>Pending</code>、索引后独立提交 <code>Indexed</code>/<code>Failed</code>，避免网络 I/O 期间长事务。进程中断则停留 <code>Pending</code>，可重建恢复。</p></div><h3 id="补偿清理-防孤儿向量" tabindex="-1">补偿清理（防孤儿向量） <a class="header-anchor" href="#补偿清理-防孤儿向量" aria-label="Permalink to &quot;补偿清理（防孤儿向量）&quot;">​</a></h3><p>摄取的一致性难点：向量已写进 Qdrant（N 条），但回写 <code>ChunkCount</code> 的 DB 更新失败——此后 DB 记 0、向量库有 N，后续按 <code>ChunkCount(=0)</code> 无法清理，<strong>孤儿向量持续污染检索</strong>。领域服务的处理：回写 DB 失败时，<strong>补偿清理</strong>刚写入的向量（<code>RemoveDocumentAsync(documentId, writtenChunkCount)</code>）以保证 DB 与向量库一致；补偿本身再失败则落错误日志（可能残留孤儿，需人工介入）。删除/重建也据 <code>ChunkCount</code> 枚举全部确定性主键来清向量。</p><h3 id="检索与问答" tabindex="-1">检索与问答 <a class="header-anchor" href="#检索与问答" aria-label="Permalink to &quot;检索与问答&quot;">​</a></h3><p><code>KnowledgeQueryAppService.QueryAsync</code>（<code>[HttpPost]</code>，<code>knowledge_base:execute</code>）：</p><ol><li><code>topK</code> 收敛到 <code>1~20</code>（默认取 RAG 配置的 <code>DefaultTopK</code>）。</li><li>按<strong>当前租户</strong>过滤检索（无租户上下文=平台全局 <code>TenantId=0</code>）：<code>IKnowledgeRetriever.RetrieveAsync(query, topK, filter, provider)</code>。</li><li>返回命中片段（<code>Citations</code>：文档 id / 序号 / 标题 / 来源 / 相似度 / 文本）。</li><li>若 <code>Answer=true</code> 且有命中：<code>IRagPromptAugmenter.Augment</code> 把片段注入 prompt，走会话门面 <code>IXiHanAiService.ChatAsync</code> 生成<strong>带引用的答案</strong>（<code>Answer</code> 字段）。</li></ol><p>请求里的 <code>Provider</code> 编码<strong>同时用于嵌入与会话</strong>；<code>Answer=false</code> 时只返回命中片段不调用大模型。</p><h3 id="rag-部署配置" tabindex="-1">RAG 部署配置 <a class="header-anchor" href="#rag-部署配置" aria-label="Permalink to &quot;RAG 部署配置&quot;">​</a></h3><p>向量库连接属<strong>部署级基础设施配置</strong>，走 <code>appsettings</code> 的 <code>XiHan:AI:Rag</code> 节（<code>XiHanRagOptions</code>）：</p><table tabindex="0"><thead><tr><th>字段</th><th>默认</th><th>说明</th></tr></thead><tbody><tr><td><code>QdrantHost</code></td><td><code>localhost</code></td><td>Qdrant 主机（gRPC）</td></tr><tr><td><code>QdrantPort</code></td><td><code>6334</code></td><td>gRPC 端口</td></tr><tr><td><code>QdrantHttps</code></td><td><code>false</code></td><td>Qdrant Cloud 用 <code>true</code> + <code>QdrantApiKey</code></td></tr><tr><td><code>QdrantApiKey</code></td><td><code>null</code></td><td>云端鉴权</td></tr><tr><td><code>DefaultTopK</code></td><td><code>5</code></td><td>检索默认返回条数</td></tr></tbody></table><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;XiHan&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;AI&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;Rag&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;QdrantHost&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;localhost&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;QdrantPort&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6334</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;QdrantHttps&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;DefaultTopK&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><hr><h2 id="agent-与-mcp" tabindex="-1">Agent 与 MCP <a class="header-anchor" href="#agent-与-mcp" aria-label="Permalink to &quot;Agent 与 MCP&quot;">​</a></h2><p>BasicApp 通过框架把知识检索能力对外暴露为标准工具，两条投影链路：</p><p><strong>技能 → 对话工具 / MCP 工具</strong>：<code>KnowledgeRetrieveSkill</code> 实现框架 <code>IAiSkill</code>（名 <code>knowledge_retrieve</code>），在模块 <code>AddAISkills()</code> 里注册为单例。框架 <code>DefaultAiSkillRegistry</code> <strong>构造时自动收纳</strong> DI 里全部 <code>IAiSkill</code>，一处注册即同时可用于：</p><ul><li><strong>对话工具</strong>：<code>skill.AsFunction()</code> 产出 <code>AIFunction</code>，可挂进 Agent 的工具集（框架 <code>IXiHanAgentFactory</code> 经 <code>IChatClient.AsAIAgent(...)</code> 产出 MAF 原生 <code>AIAgent</code>，支持工具调用与多轮会话）。</li><li><strong>MCP tools</strong>：框架把技能 <code>AsFunction()</code> 经官方 <code>McpServerTool.Create</code> 桥接进 MCP 工具集。</li></ul><p><code>KnowledgeRetrieveSkill</code> <strong>只读、无副作用</strong>，故 MCP 暴露安全（无需批准）。经 MCP 调用时无用户/租户上下文（应用管理的 key 为平台级凭据），检索<strong>不加租户过滤</strong>（知识库文档视为平台级）；<code>topK</code> 内部收敛 <code>1~20</code>。</p><div class="warning custom-block"><p class="custom-block-title">工具会被自动执行</p><p>框架工厂套了 <code>UseFunctionInvocation</code>、MAF Agent 内部也套 <code>FunctionInvokingChatClient</code>——工具/技能会被<strong>自动调用、无人工批准</strong>。当前 v1 技能均只读（知识检索）安全；将来接入有副作用的技能须自行加批准/审计。</p></div><h3 id="mcp-server-应用管理-key-fail-closed" tabindex="-1">MCP Server（应用管理 key，fail-closed） <a class="header-anchor" href="#mcp-server-应用管理-key-fail-closed" aria-label="Permalink to &quot;MCP Server（应用管理 key，fail-closed）&quot;">​</a></h3><p>MCP Server 的启用与暴露由 WebHost 负责，配置节 <code>XiHan:AI:Mcp</code>（<code>XiHanMcpOptions</code>）：</p><table tabindex="0"><thead><tr><th>字段</th><th>默认</th><th>说明</th></tr></thead><tbody><tr><td><code>Enabled</code></td><td><code>false</code></td><td>是否启用（默认关）</td></tr><tr><td><code>ApiKey</code></td><td><code>null</code></td><td><strong>应用管理的</strong>访问密钥，外部 MCP 客户端须携带</td></tr><tr><td><code>HeaderName</code></td><td><code>X-Api-Key</code></td><td>携带密钥的请求头（或 <code>Authorization: Bearer</code>）</td></tr><tr><td><code>Path</code></td><td><code>/mcp</code></td><td>端点路径</td></tr><tr><td><code>Stateless</code></td><td><code>true</code></td><td>无状态 HTTP（检索类工具足够）</td></tr></tbody></table><p>鉴权是<strong>应用管理的 key</strong>、不是用户令牌：<code>/mcp</code> 端点 <code>AllowAnonymous()</code> 绕过全局授权 FallbackPolicy，改由 <code>McpApiKeyEndpointFilter</code> 端点过滤器守门——请求头不匹配即 401。</p><p><strong>fail-closed</strong>：<code>IsExposable = Enabled &amp;&amp; !string.IsNullOrWhiteSpace(ApiKey)</code>。<strong>未启用或未配 <code>ApiKey</code> 则根本不注册、不映射 <code>/mcp</code> 端点</strong>——宁可不暴露，也不裸奔。</p><hr><h2 id="部署前置" tabindex="-1">部署前置 <a class="header-anchor" href="#部署前置" aria-label="Permalink to &quot;部署前置&quot;">​</a></h2><p>启用 AI / 知识库能力前，须准备：</p><ol><li><strong>Qdrant 向量库</strong>：可连接的 Qdrant 实例，<code>XiHan:AI:Rag</code> 节配好 <code>QdrantHost</code>/<code>QdrantPort</code>（云端另加 <code>QdrantHttps</code> + <code>QdrantApiKey</code>）。未注册向量库而调用 RAG 会因缺依赖失败。</li><li><strong>嵌入模型对齐 <code>1536</code> 维</strong>：默认 <code>text-embedding-3-small</code>（1536 维）。换维度须改框架常量并<strong>重建 Qdrant 集合</strong>。</li><li><strong>重建数据库</strong>：BasicApp 采用重建库策略（不做向后兼容），首次启动自动建表并跑种子；AI 相关表 <code>Sys_Ai_Provider</code> / <code>Sys_Knowledge_Document</code> 随之建立。</li><li><strong>provider 配置入库</strong>：库化管理下 provider 不写 appsettings——建库后在前端「AI 提供商」页新增配置、填好 <code>Model</code>/<code>EmbeddingModel</code>/<code>ApiKey</code>、设默认并测连接。</li><li><strong>（可选）MCP</strong>：需要对外暴露 MCP tools 时，<code>XiHan:AI:Mcp</code> 显式 <code>Enabled=true</code> 并配 <code>ApiKey</code>。</li><li><strong>多实例</strong>：共享 Data Protection 密钥环，否则各实例无法互相解密 provider 密钥。</li></ol><p>种子说明：AI provider 与知识库各占独立种子 Order 段（<code>200-204</code> / <code>205-208</code>，晚于 Saas 的 <code>10-37</code> 与代码生成的 <code>100-105</code>），链内顺序均为「操作字典 → 资源 → 权限 → 菜单 → 角色授权」，权限<strong>仅授超管</strong>（其余角色/租户按需在权限管理里下放）。</p><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./../framework/packages/ai">框架 · XiHan.Framework.AI</a>：底层 provider 解析/热切换、RAG 切片检索、Agent/MCP 桥接的抽象与默认实现</li><li><a href="./permissions">权限模型</a>：<code>module:resource:action</code> 权限码、数据范围、字段级脱敏</li><li><a href="./multi-tenancy">多租户</a>：字段级隔离与 <code>TenantId=0</code> 全局约定</li><li><a href="./deployment">部署</a>：环境要求与重建库策略</li></ul>`,71)])])}const k=d(a,[["render",s]]);export{g as __pageData,k as default};
